import{_ as o,o as e,c as t,ai as r}from"./chunks/framework.ampVZV4B.js";const h=JSON.parse('{"title":"秒杀系统架构设计","description":"","frontmatter":{},"headers":[],"relativePath":"scenarios/seckill.md","filePath":"scenarios/seckill.md"}'),i={name:"scenarios/seckill.md"};function n(l,s,a,d,g,c){return e(),t("div",null,[...s[0]||(s[0]=[r('<h1 id="秒杀系统架构设计" tabindex="-1">秒杀系统架构设计 <a class="header-anchor" href="#秒杀系统架构设计" aria-label="Permalink to “秒杀系统架构设计”">​</a></h1><hr><h3 id="❓-面试官-如果让你设计一个-10-万人抢-100-台-iphone-的秒杀系统-你怎么防止超卖-如何扛住高并发-【中高级】" tabindex="-1">❓ 面试官：如果让你设计一个 10 万人抢 100 台 iPhone 的秒杀系统，你怎么防止超卖？如何扛住高并发？【中高级】 <a class="header-anchor" href="#❓-面试官-如果让你设计一个-10-万人抢-100-台-iphone-的秒杀系统-你怎么防止超卖-如何扛住高并发-【中高级】" aria-label="Permalink to “❓ 面试官：如果让你设计一个 10 万人抢 100 台 iPhone 的秒杀系统，你怎么防止超卖？如何扛住高并发？【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><blockquote><p>这是一个极其经典的系统设计题，几乎是中级后端面试的必考项目。千万不要一上来就说查数据库。</p></blockquote><p><strong>💡 一句话总结（先抛整体架构结论）：</strong> 秒杀的核心思想是：<strong>“层层拦截、流量削峰、异步处理、内存预扣”</strong>。绝对不能让 10 万个请求直接打到 MySQL 上。通过 Nginx、网关、Redis、MQ 构建多道防线，最终真正落库的可能只有几百个请求。</p><p><strong>📝 详细的架构推演设计（按生命周期分层答）：</strong></p><p><strong>第一道防线：前端与 CDN（拦截 80% 的无效/重复请求）</strong></p><ol><li><strong>防连点</strong>：用户点击“抢购”按钮后，按钮立刻置灰变暗 5 秒，防止小白用户疯狂疯狂狂点。</li><li><strong>页面静态化</strong>：秒杀的商品图片、详情介绍等全部做成静态 HTML，推送到 CDN。用户刷新页面根本不会打到我们的后端接口。</li></ol><p><strong>第二道防线：网关与风控拦截（防刷与限流）</strong></p><ol><li><strong>IP 与黑名单限流</strong>：在 Nginx 或 SpringCloud Gateway 层面，利用 Redis 记录同一个 IP 一秒钟的访问次数，超过 10 次直接返回“系统繁忙”（拦截掉机器刷单脚本）。</li><li><strong>隐藏秒杀接口</strong>：秒杀没开始前，前端拿不到真实的秒杀 URL。开抢瞬间才通过一个接口返回真实的、带动态 Token 的秒杀地址，防止黑客提前写脚本死循环调用真实接口。</li></ol><p><strong>第三道防线：Redis 内存预扣减（核心防超卖）</strong> 这是真正的抗压核心！<strong>绝对不能用 <code>update sku set stock = stock -1 where id = 1 and stock &gt; 0</code> 这种方式直接去压测数据库</strong>，数据库的行锁会瞬间死锁或者连接池打满。</p><ul><li><strong>预热库存</strong>：秒杀前，提前把这 100 台 iPhone 的库存数量扔到 Redis 里（比如 <code>set seckill_sku_1001 100</code>）。</li><li><strong>Lua 脚本扣库存（极其关键）</strong>：使用 Redis 的 Lua 脚本进行扣减（因为 Lua 脚本在 Redis 里执行是原子性的，不会有并发覆盖问题）。脚本逻辑是：“查库存，如果 &gt; 0，则扣减 1，返回成功；否则返回失败”。</li><li>这个阶段，10 万个并发打到 Redis，Redis 单机能扛 8-10 万 QPS，非常轻松。最后只有 100 个请求拿到了 <code>成功</code> 的标志。</li></ul><p><strong>第四道防线：MQ 异步落库（保护数据库）</strong></p><ul><li>上面那 100 个在 Redis 里抢到库存的用户，系统不是立刻给他们创建订单查数据库。</li><li>而是<strong>把这 100 个人包装成一条消息发到 RocketMQ/RabbitMQ</strong>，然后立刻给用户前端返回：“您已抢购成功，正在排队生成订单中...”。</li><li>后台有几个平缓的消费者去订阅这个 MQ，<strong>慢条斯理地、以每秒几十个的速度去写 MySQL 订单表</strong>。这样 MySQL 就如同被保护在温室里，毫无压力。</li></ul><hr><h3 id="❓-面试官-你在上面提到用-redis-预扣减库存-那如果用户下了单-redis-库存扣了-但是最后没付款取消了-这时候怎么回退库存保证别人还能买" tabindex="-1">❓ 面试官：你在上面提到用 Redis 预扣减库存，那如果用户下了单（Redis 库存扣了），但是最后没付款取消了，这时候怎么回退库存保证别人还能买？ <a class="header-anchor" href="#❓-面试官-你在上面提到用-redis-预扣减库存-那如果用户下了单-redis-库存扣了-但是最后没付款取消了-这时候怎么回退库存保证别人还能买" aria-label="Permalink to “❓ 面试官：你在上面提到用 Redis 预扣减库存，那如果用户下了单（Redis 库存扣了），但是最后没付款取消了，这时候怎么回退库存保证别人还能买？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 这就需要结合<strong>延迟队列</strong>或者<strong>定时任务</strong>做“库存回滚”机制。</p><p><strong>📝 实战解决方案：</strong></p><ol><li>发送下单消息给普通队列的同时，发送一条<strong>延迟时间为 15 分钟的延迟消息</strong>。</li><li>15 分钟后，消费者收到这条延迟消息，去查一下数据库的订单状态。</li><li>如果订单状态是“已支付”，那没事了，直接丢弃消息。</li><li>如果订单状态是“待支付”或“已取消”，说明用户鸽了。这时候消费者去执行<strong>回滚操作</strong>：调用 Redis 将刚才扣掉的那 1 个库存加回来（利用 Lua 脚本或者 <code>incr</code> 命令），同时把数据库的订单标记为关闭。这样其他用户就可以继续抢了。</li></ol>',21)])])}const _=o(i,[["render",n]]);export{h as __pageData,_ as default};
